}

score_col &lt;- intersect(c("score", "statistic", "logFC", "avg_log2FC"), names(micbus_res))[1]
padj_col &lt;- intersect(c("p_adj", "padj", "adj.P.Val", "q_value", "FDR"), names(micbus_res))[1]

